// src/pages/Register.jsx

import { useState } from "react";

import axios from "axios";

export default function Register() {

  const [form, setForm] =
    useState({

      role: "customer",

      skills: []

    });

  const jobs = [

    "Electrician",

    "Plumber",

    "Painter",

    "Carpenter",

    "Cleaner",

    "Technician",

    "Welder",

    "Driver"

  ];

  const handleSkills = (e) => {

    const values = Array.from(

      e.target.selectedOptions,

      option => option.value

    );

    setForm({

      ...form,

      skills: values

    });
  };

  const register = async () => {

    try {

      const res = await axios.post(

        "http://localhost:5000/api/auth/register",

        form

      );

      localStorage.setItem(

        "user",

        JSON.stringify(res.data.user)

      );

      if (form.role === "customer") {

        window.location =
          "/customer-dashboard";

      } else {

        window.location =
          "/labour-dashboard";

      }

    } catch (err) {

      alert(

        err.response?.data?.message ||

        "Registration Failed"

      );
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <div style={styles.header}>

          <h1 style={styles.title}>
            Create Account
          </h1>

          <p style={styles.subtitle}>
            Join DailyMajdoor platform
          </p>

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Account Type
          </label>

          <select
            style={styles.input}
            onChange={(e) =>
              setForm({
                ...form,
                role: e.target.value
              })
            }
          >

            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Full Name
          </label>

          <input
            style={styles.input}
            placeholder="Enter name"
            onChange={(e) =>
              setForm({
                ...form,
                name: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Email
          </label>

          <input
            style={styles.input}
            placeholder="Enter email"
            onChange={(e) =>
              setForm({
                ...form,
                email: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Password
          </label>

          <input
            type="password"
            style={styles.input}
            placeholder="Enter password"
            onChange={(e) =>
              setForm({
                ...form,
                password: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Phone
          </label>

          <input
            style={styles.input}
            placeholder="Enter phone"
            onChange={(e) =>
              setForm({
                ...form,
                phone: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            City
          </label>

          <input
            style={styles.input}
            placeholder="Enter city"
            onChange={(e) =>
              setForm({
                ...form,
                city: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <label style={styles.label}>
            Area
          </label>

          <input
            style={styles.input}
            placeholder="Enter area"
            onChange={(e) =>
              setForm({
                ...form,
                area: e.target.value
              })
            }
          />

        </div>

        {form.role === "labour" && (

          <div style={styles.field}>

            <label style={styles.label}>
              Select Jobs
            </label>

            <select
              multiple
              style={styles.multi}
              onChange={handleSkills}
            >

              {jobs.map((job, index) => (

                <option
                  key={index}
                  value={job}
                >
                  {job}
                </option>

              ))}

            </select>

          </div>

        )}

        <button
          style={styles.button}
          onClick={register}
        >
          Create Account
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "40px",
    fontFamily: "Arial"
  },

  card: {
    width: "460px",
    background: "white",
    borderRadius: "18px",
    padding: "35px",
    boxShadow:
      "0 6px 20px rgba(0,0,0,0.06)"
  },

  header: {
    marginBottom: "25px",
    textAlign: "center"
  },

  title: {
    color: "#111827"
  },

  subtitle: {
    color: "#6b7280"
  },

  field: {
    marginBottom: "18px"
  },

  label: {
    display: "block",
    marginBottom: "8px"
  },

  input: {
    width: "100%",
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    boxSizing: "border-box"
  },

  multi: {
    width: "100%",
    height: "120px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    padding: "10px"
  },

  button: {
    width: "100%",
    background: "#2563eb",
    color: "white",
    padding: "15px",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  }

};
